#include <stdio.h>
#include <string.h>

int isPalindrome(char *s) {
    int len = strlen(s);
    for (int i = 0; i < len / 2; i++) {
        if (s[i] != s[len - i - 1]) return 0;
    }
    return 1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char A[1001], B[1001], C[1001];
        scanf("%s %s %s", A, B, C);
        int count = 0;
        for (int i = 0; i < strlen(A); i++) {
            for (int j = i + 1; j <= strlen(A); j++) {
                for (int k = 0; k < strlen(B); k++) {
                    for (int l = k + 1; l <= strlen(B); l++) {
                        for (int m = 0; m < strlen(C); m++) {
                            for (int n = m + 1; n <= strlen(C); n++) {
                                char temp[3003];
                                strncpy(temp, A + i, j - i);
                                temp[j - i] = '\0';
                                strcat(temp, B + k);
                                strcat(temp, C + m);
                                if (isPalindrome(temp)) count++;
                            }
                        }
                    }
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

