#include <iostream>
#include <string>
using namespace std;

bool isPalindrome(string s) {
    int len = s.length();
    for (int i = 0; i < len / 2; i++) {
        if (s[i] != s[len - i - 1]) return false;
    }
    return true;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        string A, B, C;
        cin >> A >> B >> C;
        int count = 0;
        for (int i = 0; i < A.length(); i++) {
            for (int j = i + 1; j <= A.length(); j++) {
                for (int k = 0; k < B.length(); k++) {
                    for (int l = k + 1; l <= B.length(); l++) {
                        for (int m = 0; m < C.length(); m++) {
                            for (int n = m + 1; n <= C.length(); n++) {
                                string temp = A.substr(i, j - i) + B.substr(k, l - k) + C.substr(m, n - m);
                                if (isPalindrome(temp)) count++;
                            }
                        }
                    }
                }
            }
        }
        cout << count << endl;
    }
    return 0;
}

